export default async function AdminPage() {
  const { isAdmin, session } = await verifyAdmin()

  if (!isAdmin) {
    unauthorized()
  }

  return (
    <main style={{ maxWidth: 800, margin: '0 auto', padding: '2rem' }}>
      <h1>Admin Dashboard</h1>
      <p>Welcome, {session?.name}.</p>

